803→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
804→        user_reaction: userReactionMap.get(journal.id) || null
805→    }))
806→
807→    const hasMore = data?.length > parsedLimit;
808→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
